(ns
 destr.gen-test
 (:require
  [clojure.test :refer [deftest is]]
  [destr.gen :refer [normalize-destructuring]]))

(deftest
 test-destructure-0
 (let
  [expected
   '[?vec2
     ?p1
     s
     (clojure.core/nth ?vec2 0 nil)
     g
     (clojure.core/nth ?vec2 1 nil)]]
  (is
   (=
    expected
    (normalize-destructuring (destructure '[[s g] p__9000]))))))

