(deftest
 test-destructure-15
 (let
  [expected
   '[diamond
     (reduce
      (fn*
       [p1__19630# p2__19631#]
       (apply derive (cons p1__19630# p2__19631#)))
      (make-hierarchy)
      [[:clojure.test-clojure.multimethods/mammal
        :clojure.test-clojure.multimethods/animal]
       [:clojure.test-clojure.multimethods/bird
        :clojure.test-clojure.multimethods/animal]
       [:clojure.test-clojure.multimethods/griffin
        :clojure.test-clojure.multimethods/mammal]
       [:clojure.test-clojure.multimethods/griffin
        :clojure.test-clojure.multimethods/bird]])
     bird-no-more
     (underive
      diamond
      :clojure.test-clojure.multimethods/griffin
      :clojure.test-clojure.multimethods/bird)]]
  (is
   (=
    expected
    (normalize-destructuring
     (destructure
      '[diamond
        (reduce
         (fn*
          [p1__19630# p2__19631#]
          (apply derive (cons p1__19630# p2__19631#)))
         (make-hierarchy)
         [[:clojure.test-clojure.multimethods/mammal
           :clojure.test-clojure.multimethods/animal]
          [:clojure.test-clojure.multimethods/bird
           :clojure.test-clojure.multimethods/animal]
          [:clojure.test-clojure.multimethods/griffin
           :clojure.test-clojure.multimethods/mammal]
          [:clojure.test-clojure.multimethods/griffin
           :clojure.test-clojure.multimethods/bird]])
        bird-no-more
        (underive
         diamond
         :clojure.test-clojure.multimethods/griffin
         :clojure.test-clojure.multimethods/bird)]))))))

