(deftest
 test-destructure-46
 (let
  [expected
   '[long+
     (fn ([a b] (+ (long a) (long b))) ([a] a) ([] 0))
     mapinc
     (map inc)
     mapinclong
     (map (comp inc long))
     arange
     (range 100)
     avec
     (into [] arange)
     alist
     (into () arange)
     obj-array
     (into-array arange)
     int-array
     (into-array
      Integer/TYPE
      (map (fn* [p1__36448#] (Integer. (int p1__36448#))) arange))
     long-array
     (into-array Long/TYPE arange)
     float-array
     (into-array Float/TYPE arange)
     char-array
     (into-array Character/TYPE (map char arange))
     double-array
     (into-array Double/TYPE arange)
     byte-array
     (into-array Byte/TYPE (map byte arange))
     int-vec
     (into (vector-of :int) arange)
     long-vec
     (into (vector-of :long) arange)
     float-vec
     (into (vector-of :float) arange)
     char-vec
     (into (vector-of :char) (map char arange))
     double-vec
     (into (vector-of :double) arange)
