   (=
    expected
    (normalize-destructuring
     (destructure
      '[form
        (read* (doto rdr (unread \()) true nil opts pending-forms)
        rargs
        (rseq arg-env)
        args
        (if
         rargs
         (let
          [higharg (long (key (first rargs)))]
          (let
           [args
            (loop
             [i 1 args (transient [])]
             (if
              (> i higharg)
              (persistent! args)
              (recur
               (inc i)
               (conj! args (or (get arg-env i) (garg i))))))
            args
            (if (arg-env -1) (conj args '& (arg-env -1)) args)]
           args))
         [])]))))))

