   '[closed-over-in-catch
     (let
      [x :foo]
      (fn [] (try (throw (Exception. "boom")) (catch Exception e x))))
     a
     (atom nil)
     closed-over-in-finally
     (fn [] (try :ret (finally (reset! a :run))))]]
  (is
   (=
    expected
    (normalize-destructuring
     (destructure
      '[closed-over-in-catch
        (let
         [x :foo]
         (fn
          []
          (try (throw (Exception. "boom")) (catch Exception e x))))
        a
        (atom nil)
        closed-over-in-finally
        (fn [] (try :ret (finally (reset! a :run))))]))))))

